```class Solution {
    public long mostPoints(int[][] questions) {
        int n = questions.length;
        long[] dp = new long[n];
        dp[0] = questions[0][0];
        for (int i = 1; i < n; i++) {
            dp[i] = Math.max(dp[i - 1], dp[i - 1] - questions[i - 1][0] + questions[i][0]);
        }
        return dp[n - 1];
    }
}```
